"use client";

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  StatGroup,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  KanbanBoard,
  DataTable,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  RelationshipRow,
  Meter,
  Alert,
  AlertTitle,
  AlertDescription,
  Badge,
  Button,
  Separator,
  formatCurrency,
  formatPercent,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconCake,
  IconRefresh,
  IconCoin,
  IconChevronRight,
  IconUserCircle,
  IconCalendarEvent,
} from "@tabler/icons-react";
import { CommissionBreakdown } from "./CommissionBreakdown";
import { CustomerDetailSheet } from "./CustomerDetailSheet";
import {
  ME,
  GOAL,
  ALERTS,
  PROSPECTS,
  STAGES,
  APPOINTMENTS,
  APPT_TONE,
  BOOK,
  PRODUCT_TONE,
  STATE_TONE,
  type Prospect,
  type BookCustomer,
  type AlertKind,
} from "./data";

const ALERT_ICON: Record<AlertKind, React.ReactNode> = {
  更新: <IconRefresh size={18} aria-hidden />,
  満期: <IconCoin size={18} aria-hidden />,
  誕生日: <IconCake size={18} aria-hidden />,
  失効リスク: <IconAlertTriangle size={18} aria-hidden />,
};

export default function InsuranceAgentPortal() {
  const [selected, setSelected] = React.useState<BookCustomer | null>(null);
  const [open, setOpen] = React.useState(false);

  const openCustomer = React.useCallback((c: BookCustomer) => {
    setSelected(c);
    setOpen(true);
  }, []);

  // ── KPI 値の算出 ───────────────────────────────────────────
  const acPct = GOAL.acActual / GOAL.acTarget;
  const countPct = GOAL.countActual / GOAL.countTarget;

  // ── 担当顧客テーブルの列定義 ─────────────────────────────────
  const columns = React.useMemo<ColumnDef<BookCustomer>[]>(
    () => [
      {
        accessorKey: "name",
        header: "顧客",
        cell: ({ row }) => (
          <div className="flex flex-col">
            <span className="font-medium text-foreground">
              {row.original.name}
            </span>
            <span className="text-xs text-muted-foreground">
              {row.original.kana}・{row.original.age}歳
            </span>
          </div>
        ),
      },
      {
        accessorKey: "product",
        header: "加入商品",
        cell: ({ row }) => (
          <Badge variant={PRODUCT_TONE[row.original.product]}>
            {row.original.product}
          </Badge>
        ),
      },
      {
        accessorKey: "policyNo",
        header: "証券番号",
        cell: ({ row }) => (
          <span className="font-mono text-xs text-muted-foreground">
            {row.original.policyNo}
          </span>
        ),
      },
      {
        accessorKey: "premium",
        header: "月払保険料",
        cell: ({ row }) => (
          <span className="tabular-nums">
            {formatCurrency(row.original.premium)}
          </span>
        ),
      },
      {
        accessorKey: "nextDate",
        header: "次回更新/満期",
        cell: ({ row }) =>
          row.original.nextLabel === "—" ? (
            <span className="text-muted-foreground">—</span>
          ) : (
            <span className="text-sm">
              {row.original.nextDate}
              <span className="ml-1 text-xs text-muted-foreground">
                {row.original.nextLabel}
              </span>
            </span>
          ),
      },
      {
        accessorKey: "state",
        header: "状態",
        cell: ({ row }) => (
          <Badge variant={STATE_TONE[row.original.state]}>
            {row.original.state}
          </Badge>
        ),
      },
      {
        id: "drill",
        header: "",
        enableSorting: false,
        cell: ({ row }) => (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => openCustomer(row.original)}
            aria-label={`${row.original.name} の顧客詳細を開く`}
          >
            詳細
            <IconChevronRight size={16} aria-hidden />
          </Button>
        ),
      },
    ],
    [openCustomer]
  );

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:py-8">
      {/* ── ヘッダー / 担当者↔顧客 関係 ───────────────────── */}
      <header className="mb-6">
        <p className="text-sm text-muted-foreground">募集人ポータル</p>
        <h1 className="text-2xl font-bold tracking-tight text-foreground">
          おはようございます、{ME.name} さん
        </h1>
        <p className="mt-1 text-sm text-muted-foreground">
          {ME.office}・{ME.role}（{ME.code}）／ 2026年6月27日（金）
        </p>

        <Card className="mt-4">
          <CardContent className="py-3">
            <RelationshipRow
              from={{
                name: ME.name,
                secondary: "ライフプランナー（担当者）",
                avatar: { fallback: "佐" },
              }}
              to={{
                name: `担当顧客 ${BOOK.length}名`,
                secondary: "保有契約のブック",
                avatar: { fallback: <IconUserCircle size={20} aria-hidden /> },
              }}
              relationshipLabel="担当"
              trailing={
                <Badge variant="success">継続率 {formatPercent(GOAL.retentionRate)}</Badge>
              }
            />
          </CardContent>
        </Card>
      </header>

      {/* ── 今日のサマリ（KPI strip）─────────────────────── */}
      <section aria-labelledby="kpi-heading" className="mb-6">
        <h2 id="kpi-heading" className="sr-only">
          今日のサマリ
        </h2>
        <StatGroup
          cols={{ base: 2, md: 4 }}
          items={[
            {
              label: "月間AC達成率",
              value: formatPercent(acPct),
              change: `${formatCurrency(GOAL.acActual)} / ${formatCurrency(
                GOAL.acTarget
              )}`,
              trend: "up",
              tone: "positive",
            },
            {
              label: "今月成約件数",
              value: `${GOAL.countActual}件`,
              change: `目標 ${GOAL.countTarget}件`,
              trend: countPct >= 1 ? "up" : "flat",
              hint: `達成率 ${formatPercent(countPct)}`,
            },
            {
              label: "13ヶ月継続率",
              value: formatPercent(GOAL.retentionRate),
              change: `目標 ${formatPercent(GOAL.retentionTarget)}`,
              trend: "up",
              tone: "positive",
            },
            {
              label: "今月アポ件数",
              value: `${GOAL.appointments}件`,
              hint: "訪問・Web・電話",
            },
          ]}
        />

        {/* 目標進捗 Meter */}
        <Card className="mt-4">
          <CardHeader>
            <CardTitle as="h3">月間目標 進捗</CardTitle>
            <CardDescription>残り4営業日</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            <Meter
              label="AC（保険料換算）"
              value={GOAL.acActual}
              max={GOAL.acTarget}
              direction="higher-is-better"
              tone="primary"
              formatValue={(v) => formatCurrency(v)}
            />
            <Meter
              label="成約件数"
              value={GOAL.countActual}
              max={GOAL.countTarget}
              unit="件"
              direction="higher-is-better"
              tone="success"
            />
          </CardContent>
        </Card>
      </section>

      {/* ── 要対応アラート ─────────────────────────────── */}
      <section aria-labelledby="alert-heading" className="mb-6">
        <h2
          id="alert-heading"
          className="mb-3 text-lg font-semibold text-foreground"
        >
          要対応アラート（{ALERTS.length}）
        </h2>
        <div className="grid gap-3 sm:grid-cols-2">
          {ALERTS.map((a) => (
            <Alert key={a.id} variant={a.severity}>
              <div className="flex items-start gap-2">
                <span aria-hidden>{ALERT_ICON[a.kind]}</span>
                <div className="min-w-0 flex-1">
                  <AlertTitle className="flex items-center gap-2">
                    <span>{a.kind}</span>
                    <Badge variant="outline">{a.due}</Badge>
                  </AlertTitle>
                  <AlertDescription>
                    {a.customer} 様 — {a.detail}
                  </AlertDescription>
                </div>
              </div>
            </Alert>
          ))}
        </div>
      </section>

      {/* ── 見込み客パイプライン（Kanban）─────────────────── */}
      <section aria-labelledby="pipeline-heading" className="mb-6">
        <div className="mb-3 flex items-baseline justify-between">
          <h2
            id="pipeline-heading"
            className="text-lg font-semibold text-foreground"
          >
            見込み客パイプライン
          </h2>
          <span className="text-sm text-muted-foreground">
            想定AC合計{" "}
            {formatCurrency(
              PROSPECTS.filter((p) => p.stage !== "成約").reduce(
                (s, p) => s + p.ac,
                0
              )
            )}
          </span>
        </div>
        <KanbanBoard<Prospect>
          columns={STAGES.map((s) => ({ id: s.id, title: s.id, tone: s.tone }))}
          items={PROSPECTS}
          getItemId={(p) => p.id}
          getColumnId={(p) => p.stage}
          columnWidth={250}
          renderCard={(p) => (
            <div className="flex flex-col gap-1.5">
              <div className="flex items-center justify-between gap-2">
                <span className="font-medium text-foreground">{p.name}</span>
                <span className="text-xs text-muted-foreground">{p.age}歳</span>
              </div>
              <Badge variant={PRODUCT_TONE[p.product]}>{p.product}</Badge>
              <div className="text-xs text-muted-foreground">
                想定保険料 {formatCurrency(p.premium)}/月・AC{" "}
                {formatCurrency(p.ac)}
              </div>
              <Separator className="my-0.5" />
              <div className="flex items-start gap-1 text-xs">
                <IconCalendarEvent
                  size={14}
                  aria-hidden
                  className="mt-0.5 shrink-0 text-muted-foreground"
                />
                <span className="text-foreground">
                  {p.nextAction}
                  <span className="ml-1 text-muted-foreground">
                    （{p.nextDue}）
                  </span>
                </span>
              </div>
              <div className="text-[11px] text-muted-foreground">
                紹介元：{p.source}
              </div>
            </div>
          )}
        />
      </section>

      <div className="grid gap-6 lg:grid-cols-2">
        {/* ── 本日のアポ・タスク（Timeline）──────────────── */}
        <section aria-labelledby="appt-heading">
          <Card>
            <CardHeader>
              <CardTitle as="h2">本日のアポ・タスク</CardTitle>
              <CardDescription>
                {APPOINTMENTS.length}件・時系列
              </CardDescription>
            </CardHeader>
            <CardContent>
              <Timeline>
                {APPOINTMENTS.map((appt, i) => (
                  <TimelineItem
                    key={appt.id}
                    connector={i < APPOINTMENTS.length - 1}
                    variant={APPT_TONE[appt.kind]}
                  >
                    <TimelineTime>{appt.time}</TimelineTime>
                    <TimelineTitle className="flex flex-wrap items-center gap-2">
                      <Badge
                        variant={
                          appt.kind === "失効防止コール"
                            ? "destructive"
                            : appt.kind === "更新手続き"
                            ? "warning"
                            : "secondary"
                        }
                      >
                        {appt.kind}
                      </Badge>
                      {appt.who}
                    </TimelineTitle>
                    <TimelineDescription>{appt.what}</TimelineDescription>
                  </TimelineItem>
                ))}
              </Timeline>
            </CardContent>
          </Card>
        </section>

        {/* ── 手数料・インセンティブ内訳 ──────────────────── */}
        <section aria-labelledby="commission-heading">
          <h2 id="commission-heading" className="sr-only">
            手数料・インセンティブ内訳
          </h2>
          <CommissionBreakdown />
        </section>
      </div>

      {/* ── 担当顧客（ブック）テーブル ───────────────────── */}
      <section aria-labelledby="book-heading" className="mt-6">
        <Card>
          <CardHeader>
            <CardTitle as="h2">担当顧客（ブック）</CardTitle>
            <CardDescription>
              更新間近・誕生日・失効リスクを見渡す（{BOOK.length}名）
            </CardDescription>
          </CardHeader>
          <CardContent>
            <DataTable<BookCustomer, unknown>
              columns={columns}
              data={BOOK}
              filter={{ columnId: "name", placeholder: "顧客名で絞り込み" }}
              pageSize={8}
              onRowClick={(row) => openCustomer(row)}
            />
          </CardContent>
        </Card>
      </section>

      <CustomerDetailSheet
        customer={selected}
        open={open}
        onOpenChange={setOpen}
      />
    </main>
  );
}

"use client";

import * as React from "react";
import {
  AmountBreakdown,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  formatCurrency,
} from "@gunjo/ui";

/**
 * 当月の手数料・インセンティブ内訳。
 * 新規募集手数料 ＋ 継続手数料 ＋ 達成インセンティブ − 取消・戻入（解約戻し） = 当月手数料見込。
 * AmountBreakdown が「明細 ＋ 加算 − 控除 = 合計」をそのまま表現できる。
 */
export function CommissionBreakdown() {
  return (
    <Card>
      <CardHeader>
        <CardTitle as="h2">手数料・インセンティブ（当月見込）</CardTitle>
        <CardDescription>2026年6月度・確定前の暫定値</CardDescription>
      </CardHeader>
      <CardContent>
        <AmountBreakdown
          formatValue={(v) => formatCurrency(v)}
          lines={[
            { type: "heading", label: "募集手数料" },
            {
              label: "新規募集手数料",
              amount: 412_000,
              note: "成約8件（初年度手数料）",
            },
            {
              label: "継続手数料",
              amount: 96_400,
              note: "保有契約 142件の継続分",
            },
            {
              type: "subtotal",
              label: "手数料小計",
              amount: 508_400,
            },
            { type: "heading", label: "インセンティブ・調整" },
            {
              label: "月間達成インセンティブ",
              amount: 72_000,
              note: "件数達成率 67%（按分支給）",
            },
            {
              label: "取消・戻入（解約戻し）",
              amount: 34_500,
              kind: "subtract",
              note: "クーリングオフ1件・早期解約戻入",
            },
          ]}
          total={{
            label: "当月手数料見込",
            amount: 545_900,
            tone: "positive",
          }}
          formula="当月手数料見込 ＝ 新規募集手数料 ＋ 継続手数料 ＋ 達成インセンティブ − 取消・戻入"
        />
      </CardContent>
    </Card>
  );
}

"use client";

import * as React from "react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  SheetClose,
  MetadataList,
  AmountBreakdown,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  Badge,
  Button,
  Separator,
  EmptyState,
  formatCurrency,
} from "@gunjo/ui";
import { IconFileText, IconPhone } from "@tabler/icons-react";
import {
  CUSTOMER_DETAIL,
  STATE_TONE,
  type BookCustomer,
} from "./data";

const RESULT_TONE: Record<string, "info" | "success" | "warning" | "secondary"> = {
  提示: "info",
  検討中: "warning",
  見送り: "secondary",
  成約: "success",
};

export function CustomerDetailSheet({
  customer,
  open,
  onOpenChange,
}: {
  customer: BookCustomer | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}) {
  const detail = customer ? CUSTOMER_DETAIL[customer.id] : undefined;

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="right"
        className="flex w-full flex-col gap-0 overflow-y-auto p-0 sm:max-w-md"
      >
        {customer && (
          <>
            <SheetHeader className="px-5 pt-5">
              <div className="flex items-center gap-2">
                <SheetTitle>{customer.name} 様</SheetTitle>
                <Badge variant={STATE_TONE[customer.state]}>
                  {customer.state}
                </Badge>
              </div>
              <SheetDescription>
                {customer.kana}・{customer.age}歳・証券 {customer.policyNo}
              </SheetDescription>
            </SheetHeader>

            <div className="flex flex-col gap-6 px-5 py-5">
              {detail ? (
                <>
                  <section aria-labelledby="cust-summary">
                    <h3
                      id="cust-summary"
                      className="mb-2 text-sm font-semibold text-foreground"
                    >
                      顧客概要
                    </h3>
                    <MetadataList items={detail.summary} />
                  </section>

                  <Separator />

                  <section aria-labelledby="cust-policies">
                    <h3
                      id="cust-policies"
                      className="mb-2 text-sm font-semibold text-foreground"
                    >
                      加入中の証券
                    </h3>
                    {detail.policies.map((pol) => (
                      <AmountBreakdown
                        key={pol.policyNo}
                        className="mb-3"
                        formatValue={(v) => formatCurrency(v)}
                        lines={[
                          {
                            label: pol.product,
                            note: `証券番号 ${pol.policyNo}・${pol.start} 始期`,
                          },
                          { label: "保険金額", amount: pol.sumInsured },
                          { label: "月払保険料", amount: pol.premium },
                        ]}
                        total={{
                          label: "年換算保険料",
                          amount: pol.premium * 12,
                        }}
                      />
                    ))}
                  </section>

                  <Separator />

                  <section aria-labelledby="cust-proposals">
                    <h3
                      id="cust-proposals"
                      className="mb-2 text-sm font-semibold text-foreground"
                    >
                      提案履歴
                    </h3>
                    <Timeline>
                      {detail.proposals.map((pr, i) => (
                        <TimelineItem
                          key={i}
                          connector={i < detail.proposals.length - 1}
                          variant={pr.result === "成約" ? "success" : "default"}
                        >
                          <TimelineTime>{pr.date}</TimelineTime>
                          <TimelineTitle className="flex items-center gap-2">
                            {pr.title}
                            <Badge variant={RESULT_TONE[pr.result]}>
                              {pr.result}
                            </Badge>
                          </TimelineTitle>
                        </TimelineItem>
                      ))}
                    </Timeline>
                  </section>

                  <Separator />

                  <section aria-labelledby="cust-next">
                    <h3
                      id="cust-next"
                      className="mb-2 text-sm font-semibold text-foreground"
                    >
                      次アクション
                    </h3>
                    <Timeline>
                      {detail.nextActions.map((na, i) => (
                        <TimelineItem
                          key={i}
                          connector={i < detail.nextActions.length - 1}
                          variant="active"
                        >
                          <TimelineTitle>{na.label}</TimelineTitle>
                          <TimelineDescription>
                            期日 {na.due}
                          </TimelineDescription>
                        </TimelineItem>
                      ))}
                    </Timeline>
                  </section>
                </>
              ) : (
                <EmptyState
                  icon={<IconFileText aria-hidden />}
                  title="詳細データは未連携です"
                  description="この顧客の証券・提案履歴は基幹システムから取得されていません。"
                  headingLevel={3}
                />
              )}
            </div>

            <SheetFooter className="mt-auto flex-row gap-2 border-t px-5 py-4">
              <Button variant="outline" className="flex-1">
                <IconPhone size={16} aria-hidden className="mr-1.5" />
                架電
              </Button>
              <SheetClose asChild>
                <Button className="flex-1">閉じる</Button>
              </SheetClose>
            </SheetFooter>
          </>
        )}
      </SheetContent>
    </Sheet>
  );
}

// 生命保険 募集人（ライフプランナー）活動ポータル — ドメインデータ
// すべてサーバー安全（関数 prop なし）。画面側で整形する。

export type ProductKind =
  | "終身保険"
  | "医療保険"
  | "学資保険"
  | "個人年金"
  | "収入保障";

export const PRODUCT_TONE: Record<
  ProductKind,
  "info" | "success" | "warning" | "secondary" | "destructive"
> = {
  終身保険: "info",
  医療保険: "success",
  学資保険: "secondary",
  個人年金: "warning",
  収入保障: "destructive",
};

// ── 担当募集人（自分）────────────────────────────────────────────
export const ME = {
  id: "lp-001",
  name: "佐藤 健司",
  role: "ライフプランナー / 第一営業部",
  office: "横浜支社",
  code: "LP-2207-0143",
} as const;

// ── 今日のサマリ（月間）──────────────────────────────────────────
export interface MonthlyGoal {
  /** 月間AC目標（保険料換算ポイント, 円相当） */
  acTarget: number;
  acActual: number;
  /** 件数目標 */
  countTarget: number;
  countActual: number;
  /** 13ヶ月継続率 */
  retentionRate: number; // 0..1
  retentionTarget: number; // 0..1
  /** 今月のアポ件数 */
  appointments: number;
}

export const GOAL: MonthlyGoal = {
  acTarget: 1_200_000,
  acActual: 868_000,
  countTarget: 12,
  countActual: 8,
  retentionRate: 0.962,
  retentionTarget: 0.95,
  appointments: 23,
};

// ── 要対応アラート ──────────────────────────────────────────────
export type AlertKind = "更新" | "満期" | "誕生日" | "失効リスク";

export interface ActionAlert {
  id: string;
  kind: AlertKind;
  customer: string;
  detail: string;
  due: string; // 表示用日付
  severity: "warning" | "destructive" | "info";
}

export const ALERTS: ActionAlert[] = [
  {
    id: "al-1",
    kind: "失効リスク",
    customer: "田辺 美咲",
    detail: "医療保険・口座振替2回連続不能（保険料 6,800円）",
    due: "6/30 まで",
    severity: "destructive",
  },
  {
    id: "al-2",
    kind: "更新",
    customer: "中村 雄一",
    detail: "収入保障（10年更新）更新案内・条件見直し",
    due: "7/15 満了",
    severity: "warning",
  },
  {
    id: "al-3",
